const largeDes =
  '超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案超长文案';
const smallDes = '一段文案，一段文案';

export const PlacementCustomer = () => {
  const [marginTop, setMarginTop] = React.useState(100);
  const [marginLeft, setMarginLeft] = React.useState(100);
  const [placement, setPlacement] = React.useState<TooltipPlacement>('top');
  const [strSize, setStrSize] = React.useState<DefaultSizeType>('small');

  return (
    <div style={{ height: '200vh' }}>
      <Space size="large" direction="vertical" style={{ width: '100%' }}>
        <Slider step={100} min={0} max={1000} value={marginTop} onChange={setMarginTop} />
        <Slider step={100} min={0} max={1000} value={marginLeft} onChange={setMarginLeft} />
        <Space align="center">
          <span>方向:</span>
          <Radio.Group
            value={placement}
            onChange={v => {
              setPlacement(v as TooltipPlacement);
              console.log('placementState change', v);
            }}
          >
            <Radio.Button value="top">上</Radio.Button>
            <Radio.Button value="bottom">下</Radio.Button>
            <Radio.Button value="left">左</Radio.Button>
            <Radio.Button value="right">右</Radio.Button>
            <Radio.Button value="topLeft">上左</Radio.Button>
            <Radio.Button value="topRight">上右</Radio.Button>
            <Radio.Button value="bottomLeft">下左</Radio.Button>
            <Radio.Button value="bottomRight">下右</Radio.Button>
            <Radio.Button value="leftTop">左上</Radio.Button>
            <Radio.Button value="leftBottom">左下</Radio.Button>
            <Radio.Button value="rightTop">右上</Radio.Button>
            <Radio.Button value="rightBottom">右下</Radio.Button>
          </Radio.Group>
        </Space>
        <Space align="center">
          <span>内容大小:</span>
          <Radio.Group value={strSize} onChange={v => setStrSize(v as DefaultSizeType)}>
            <Radio.Button value="small">短内容</Radio.Button>
            <Radio.Button value="large">长内容</Radio.Button>
          </Radio.Group>
        </Space>
      </Space>
      <Popover
        placement={placement}
        title={strSize === 'small' ? smallDes : largeDes}
        onOverlayMouseEnter={() => console.log('onOverlayMouseEnter')}
        onOverlayMouseLeave={() => console.log('onOverlayMouseLeave')}
      >
        <Button style={{ marginTop, marginLeft }}>超长文案超长文案超长文案</Button>
      </Popover>
    </div>
  );
};

